mapper.select:
SELECT (SELECT COUNT(*) FROM pi_targets t WHERE t.TARGET_USE = 'Y'
AND t.group_id = #{groupId}
) AS totalTargets,
COUNT(f.hash_id) AS totalDetections,
SUM(CASE WHEN dp.processing_flag IS NOT NULL AND dp.processing_flag != 0 THEN 1 ELSE 0 END) AS totalProcessed,
SUM(CASE WHEN dp.processing_flag IS NULL OR dp.processing_flag = 0 THEN 1 ELSE 0 END) AS totalUnprocessed,
SUM(CASE WHEN dp.approval_status = 'Y' THEN 1 ELSE 0 END) AS truePositiveCount,
SUM(CASE WHEN dp.approval_status = 'N' THEN 1 ELSE 0 END) AS falsePositiveCount,
(SELECT MAX(sh.regdate) FROM pi_scan_history sh INNER JOIN pi_targets t2 ON sh.target_id = t2.target_id AND sh.ap_no = t2.ap_no WHERE t2.TARGET_USE = 'Y'
AND t2.group_id = #{groupId}
) AS lastScanDate
FROM pi_find f INNER JOIN pi_targets t ON f.target_id = t.target_id AND f.ap_no = t.ap_no LEFT JOIN pi_data_processing dp ON f.target_id = dp.target_id AND f.ap_no = dp.ap_no AND f.hash_id = dp.hash_id WHERE t.TARGET_USE = 'Y'
AND t.group_id = #{groupId}
AND f.regdate >= #{startDate}
AND f.regdate <= #{endDate}

SELECT sub.hash_id AS findNo, sub.path AS findPath, s.data_type AS datatype, sub.regdate AS findDate, 'N' AS processYn, NULL AS trueYn, t2.name AS targetName, COALESCE(a.agent_connected_ip, tg.connected_ip) AS targetIp FROM ( SELECT f.hash_id, f.path, f.regdate, f.target_id, f.ap_no FROM pi_find f INNER JOIN pi_targets t ON f.target_id = t.target_id AND f.ap_no = t.ap_no WHERE t.TARGET_USE = 'Y'
AND t.group_id = #{groupId}
ORDER BY f.regdate DESC
LIMIT #{limit}
LIMIT 20
) sub INNER JOIN pi_targets t2 ON sub.target_id = t2.target_id AND sub.ap_no = t2.ap_no LEFT JOIN pi_summary s ON sub.target_id = s.target_id AND sub.ap_no = s.ap_no AND sub.hash_id = s.object_id LEFT JOIN pi_agents a ON t2.NAME = a.AGENT_NAME AND t2.AP_NO = a.AP_NO AND a.AGENT_USE = 'Y' LEFT JOIN pi_target_group tg ON tg.TARGET_ID = t2.TARGET_ID AND t2.AP_NO = tg.AP_NO

choose.when:
SELECT IFNULL(dt.datatype_label, s.data_type) AS label, SUM(s.match_count) AS value FROM pi_summary s INNER JOIN pi_targets t ON s.target_id = t.target_id AND s.ap_no = t.ap_no LEFT JOIN pi_datatypes dt ON s.data_type = dt.datatype_id WHERE t.TARGET_USE = 'Y'
AND t.group_id = #{groupId}
AND s.regdate >= #{startDate}
AND s.regdate <= #{endDate}
GROUP BY s.data_type, dt.datatype_label ORDER BY value DESC LIMIT 10

mapper.select:
SELECT DATE_FORMAT(f.regdate, '%Y-%m') AS label, COUNT(*) AS totalCount, 0 AS truePositiveCount, 0 AS falsePositiveCount, 0 AS processedCount FROM pi_find f INNER JOIN pi_targets t ON f.target_id = t.target_id AND f.ap_no = t.ap_no WHERE t.TARGET_USE = 'Y'
AND t.group_id = #{groupId}
AND f.regdate >= #{startDate}
AND f.regdate <= #{endDate}
/* [튜닝] 날짜 범위 미지정 시 최근 12개월로 기본 제한 */
AND f.regdate >= DATE_FORMAT(DATE_SUB(NOW(), INTERVAL 12 MONTH), '%Y-%m-01')
GROUP BY DATE_FORMAT(f.regdate, '%Y-%m') ORDER BY label ASC

SELECT t.target_id AS targetNo, t.name AS targetName, COALESCE(a.agent_connected_ip, tg.connected_ip) AS targetIp, t.group_id AS groupId, COALESCE(ptg.name, '미그룹') AS groupName, IFNULL(fc.detectionCount, 0) AS detectionCount, 0 AS processedCount, 0 AS truePositiveCount, fc.lastDetectionDate FROM pi_targets t LEFT JOIN ( SELECT target_id, ap_no, COUNT(*) AS detectionCount, MAX(regdate) AS lastDetectionDate FROM pi_find
AND regdate >= #{startDate}
AND regdate <= #{endDate}
GROUP BY target_id, ap_no ) fc ON t.target_id = fc.target_id AND t.ap_no = fc.ap_no LEFT JOIN pi_agents a ON t.NAME = a.AGENT_NAME AND t.AP_NO = a.AP_NO AND a.AGENT_USE = 'Y' LEFT JOIN pi_target_group tg ON tg.TARGET_ID = t.TARGET_ID AND t.AP_NO = tg.AP_NO LEFT JOIN pi_target_group ptg ON tg.up_idx = ptg.idx WHERE t.TARGET_USE = 'Y'
AND t.group_id = #{groupId}
ORDER BY detectionCount DESC LIMIT 100

SELECT ranked.target_id AS targetNo, t2.name AS targetName, COALESCE(a.agent_connected_ip, tg.connected_ip) AS targetIp, t2.group_id AS groupId, COALESCE(ptg.name, '미그룹') AS groupName, ranked.detectionCount, 0 AS truePositiveCount FROM ( SELECT f.target_id, f.ap_no, COUNT(*) AS detectionCount FROM pi_find f INNER JOIN pi_targets t ON f.target_id = t.target_id AND f.ap_no = t.ap_no WHERE t.TARGET_USE = 'Y'
AND t.group_id = #{groupId}
GROUP BY f.target_id, f.ap_no ORDER BY detectionCount DESC
LIMIT #{limit}
LIMIT 10
) ranked INNER JOIN pi_targets t2 ON ranked.target_id = t2.target_id AND ranked.ap_no = t2.ap_no LEFT JOIN pi_agents a ON t2.NAME = a.AGENT_NAME AND t2.AP_NO = a.AP_NO AND a.AGENT_USE = 'Y' LEFT JOIN pi_target_group tg ON tg.TARGET_ID = t2.TARGET_ID AND t2.AP_NO = tg.AP_NO LEFT JOIN pi_target_group ptg ON tg.up_idx = ptg.idx ORDER BY ranked.detectionCount DESC
